#include <stdio.h>
#include <stdlib.h>
#define MAX 10000
// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;
// Function to create a new node
Node* newNode(int key) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->val = key;
    node->left = node->right = NULL;
    return node;
}
// Function to find the minimum depth of a tree
int minDepth(Node* root) {
    if (root == NULL) return 0;
    // Create a queue for BFS
    Node** queue = (Node**) malloc(sizeof(Node*) * MAX);
    int front = 0, rear = 0;
    queue[rear++] = root;
    int depth = 0;
    while (front < rear) {
        int size = rear - front;
        depth++;
        for (int i = 0; i < size; i++) {
            Node* node = queue[front++];
            if (node->left == NULL && node->right == NULL) return depth;
            if (node->left != NULL) queue[rear++] = node->left;
            if (node->right != NULL) queue[rear++] = node->right;
        }
    }
    return depth;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Node* root = NULL;
        Node* nodes[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = newNode(i + 1);
        }
        for (int i = 0; i < N - 1; i++) {
            int pi, ci;
            char Ri;
            scanf("%d %d %c", &pi, &ci, &Ri);
            // Create nodes and assign them as children of the parent node
            if (Ri == 'L') nodes[pi - 1]->left = nodes[ci - 1];
            else nodes[pi - 1]->right = nodes[ci - 1];
            if (root == NULL) root = nodes[0];
        }
        printf("%d\n", minDepth(root));
    }
    return 0;
}

