import java.util.Queue;
import java.util.LinkedList;
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.IOException;
// Define the structure for a tree node
class Node {
    int val;
    Node left;
    Node right;
    Node(int key) {
        val = key;
        left = right = null;
    }
}
public class Main {
    // Function to find the minimum depth of a tree
    public static int minDepth(Node root) {
        if (root == null) return 0;
        Queue<Node> q = new LinkedList<Node>();
        q.add(root);
        int depth = 0;
        while (!q.isEmpty()) {
            int size = q.size();
            depth++;
            for (int i = 0; i < size; i++) {
                Node node = q.poll();
                if (node.left == null && node.right == null) return depth;
                if (node.left != null) q.add(node.left);
                if (node.right != null) q.add(node.right);
            }
        }
        return depth;
    }
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine());
            Node[] nodes = new Node[N];
            for (int i = 0; i < N; i++) {
                nodes[i] = new Node(i + 1);
            }
            Node root = null;
            for (int i = 0; i < N - 1; i++) {
                String[] input = br.readLine().split(" ");
                int pi = Integer.parseInt(input[0]);
                int ci = Integer.parseInt(input[1]);
                char Ri = input[2].charAt(0);
                // Create nodes and assign them as children of the parent node
                if (Ri == 'L') nodes[pi - 1].left = nodes[ci - 1];
                else nodes[pi - 1].right = nodes[ci - 1];
                if (root == null) root = nodes[0];
            }
            System.out.println(minDepth(root));
        }
    }
}

